const now = Math.floor(Date.now() / 1000);
const rows = ($input.item.json.stdout || '').trim().split('\n').filter(Boolean).map(l => l.split(' '));
const stale = [];
const missing = [];
const expectedSites = ['STRGuests-Tools','STRHost-Tools','STROps-Tools','STRBuyers-Tools'];
for (const site of expectedSites) {
  const row = rows.find(r => r[0] === site);
  if (!row) { missing.push(site); continue; }
  const ageHours = (now - parseInt(row[1], 10)) / 3600;
  if (ageHours > 168) stale.push(`${site}: ${ageHours.toFixed(0)}h old`);
}
if (stale.length === 0 && missing.length === 0) return [];
const lines = [
  ...missing.map(s => `• ${s}: sitemap missing — build broken?`),
  ...stale.map(line => `• ${line}`)
];
return [{ json: {
  priority: 'P0',
  source: 'sitemap-freshness',
  message: `${missing.length} missing · ${stale.length} stale (>7d):\n${lines.join('\n')}`,
  url: ($env.EMPIRE_CONSOLE_BASE_URL || 'http://localhost:4327') + '/check/audits'
}}];
